`, "",{"version":3,"sources":["webpack://./src/通用状态栏框架脚本/manager/modules/LayoutTreeNode.vue"],"names":[],"mappings":"AA6FA,aACE,YAAa,CACb,kBAAmB,CACnB,uBAAwB,CACxB,UAAW,CACX,eAAgB,CAChB,WAAY,CACZ,eAAgB,CAChB,+BAAgC,CAChC,cAAe,CACf,kCAAmC,CACnC,4BAA6B,CAC7B,eAAgB,CAChB,yCACF,CAEA,mBACE,iCAAkC,CAClC,6BACF,CAEA,uBACE,mCAAoC,CACpC,uBACF,CAEA,gBACE,UAAW,CACX,iBAAkB,CAClB,aAAc,CACd,aAAc,CACd,8BAA+B,CAC/B,cACF,CAEA,sBACE,iBACF,CAEA,cACE,UAAW,CACX,iBAAkB,CAClB,aAAc,CACd,4BACF,CAEA,eACE,MAAO,CACP,eAAgB,CAChB,sBAAuB,CACvB,kBACF,CAEA,cACE,aAAc,CACd,8BAA+B,CAC/B,gCAAiC,CACjC,aAAc,CACd,kCACF,CAEA,eACE,aAAc,CACd,8BAA+B,CAC/B,cAAe,CACf,iBACF,CAEA,kBAEA","sourcesContent":["<template>\n  <div class=\"omg-tn\">\n    <button\n      class=\"omg-tn__row\"\n      :class=\"{ 'omg-tn__row--selected': selectedId === node.id }\"\n      :style=\"{ paddingLeft: depth * 16 + 8 + 'px' }\"\n      @click.stop=\"$emit('select', node.id)\"\n    >\n      <!-- 展开/收起 -->\n      <span v-if=\"node.type === 'container'\" class=\"omg-tn__toggle\" @click.stop=\"expanded = !expanded\">\n        <i :class=\"expanded ? 'fa-solid fa-chevron-down' : 'fa-solid fa-chevron-right'\" />\n      </span>\n      <span v-else class=\"omg-tn__toggle omg-tn__toggle--leaf\" />\n\n      <!-- 图标 -->\n      <i :class=\"nodeIcon\" class=\"omg-tn__icon\" />\n\n      <!-- 标签 -->\n      <span class=\"omg-tn__label\">{{ nodeLabel }}</span>\n\n      <!-- 类型标识 -->\n      <span v-if=\"node.type === 'container'\" class=\"omg-tn__mode\">{{ modeLabel }}</span>\n      <span v-if=\"childCount > 0\" class=\"omg-tn__count\">{{ childCount }}</span>\n    </button>\n\n    <!-- 子节点 -->\n    <div v-if=\"expanded && node.children\" class=\"omg-tn__children\">\n      <LayoutTreeNode\n        v-for=\"child in node.children\"\n        :key=\"child.id\"\n        :node=\"child\"\n        :depth=\"depth + 1\"\n        :selected-id=\"selectedId\"\n        @select=\"$emit('select', $event)\"\n      />\n    </div>\n  </div>\n</template>\n\n<script setup lang=\"ts\">\nimport type { LayoutNode } from '../../data/layouts-store';\n\nconst props = defineProps<{\n  node: LayoutNode;\n  depth: number;\n  selectedId: string | null;\n}>();\n\ndefineEmits<{ select: [id: string] }>();\n\nconst expanded = ref(true);\n\nconst nodeIcon = computed(() => {\n  if (props.node.type === 'item') return 'fa-solid fa-cube';\n  switch (props.node.layoutMode) {\n    case 'flex-row':\n      return 'fa-solid fa-arrows-left-right';\n    case 'flex-col':\n      return 'fa-solid fa-arrows-up-down';\n    case 'grid':\n      return 'fa-solid fa-table-cells';\n    case 'absolute':\n      return 'fa-solid fa-expand';\n    default:\n      return 'fa-solid fa-folder';\n  }\n});\n\nconst nodeLabel = computed(() => props.node.label || (props.node.type === 'container' ? '容器' : '条目'));\n\nconst modeLabel = computed(() => {\n  switch (props.node.layoutMode) {\n    case 'flex-row':\n      return '横向';\n    case 'flex-col':\n      return '纵向';\n    case 'grid':\n      return '网格';\n    case 'absolute':\n      return '绝对';\n    case 'custom':\n      return '自定义';\n    default:\n      return '';\n  }\n});\n\nconst childCount = computed(() => props.node.children?.length ?? 0);\n</script>\n\n<style>\n/* @doc: 布局树节点 | category: 管理器模块 | desc: 递归树形节点组件 */\n\n.omg-tn__row {\n  display: flex;\n  align-items: center;\n  gap: var(--omg-space-xs);\n  width: 100%;\n  padding: 4px 8px;\n  border: none;\n  background: none;\n  color: var(--omg-text-secondary);\n  cursor: pointer;\n  border-radius: var(--omg-radius-sm);\n  font-size: var(--omg-font-sm);\n  text-align: left;\n  transition: all var(--omg-transition-fast);\n}\n\n.omg-tn__row:hover {\n  background: var(--omg-bg-tertiary);\n  color: var(--omg-text-primary);\n}\n\n.omg-tn__row--selected {\n  background: var(--omg-accent-subtle);\n  color: var(--omg-accent);\n}\n\n.omg-tn__toggle {\n  width: 14px;\n  text-align: center;\n  flex-shrink: 0;\n  font-size: 9px;\n  color: var(--omg-text-tertiary);\n  cursor: pointer;\n}\n\n.omg-tn__toggle--leaf {\n  visibility: hidden;\n}\n\n.omg-tn__icon {\n  width: 14px;\n  text-align: center;\n  flex-shrink: 0;\n  font-size: var(--omg-font-xs);\n}\n\n.omg-tn__label {\n  flex: 1;\n  overflow: hidden;\n  text-overflow: ellipsis;\n  white-space: nowrap;\n}\n\n.omg-tn__mode {\n  font-size: 9px;\n  color: var(--omg-text-tertiary);\n  background: var(--omg-bg-primary);\n  padding: 0 4px;\n  border-radius: var(--omg-radius-sm);\n}\n\n.omg-tn__count {\n  font-size: 9px;\n  color: var(--omg-text-tertiary);\n  min-width: 14px;\n  text-align: center;\n}\n\n.omg-tn__children {\n  /* no extra spacing needed; indentation is handled by padding-left */\n}\n</style>\n"],"sourceRoot":""}]);
